/* ─── Geometry helpers ─── */

double tetra_golden_ratio(void) {
    double x = 2.0;
    for (int i = 0; i < 48; i++) x = 1.0 + 1.0 / x;
    return x;
}

double tetra_derive_constant(const char *name, int steps) {
    (void)steps;
    if (strcmp(name, "phi") == 0) return 1.61803398874989484820;
    if (strcmp(name, "pi") == 0)  return 3.14159265358979323846;
    return 1.0;
}

